const N_IMGF: usize = 469;
fn main() {
    let path = std::env::args().nth(1).unwrap_or_else(|| "zenpng_lossless_ssim2_d8_cases.bin".to_string());
    let raw = std::fs::read(&path).expect("read verify cases bin");
    let rec = (N_IMGF + 2) * 4;
    let n = raw.len() / rec;
    let mut ok = 0usize;
    for k in 0..n {
        let base = k * rec;
        let mut feats = vec![0f32; N_IMGF];
        for i in 0..N_IMGF {
            let o = base + i*4;
            feats[i] = f32::from_le_bytes([raw[o],raw[o+1],raw[o+2],raw[o+3]]);
        }
        let o = base + N_IMGF*4;
        let zq = f32::from_le_bytes([raw[o],raw[o+1],raw[o+2],raw[o+3]]);
        let o2 = base + (N_IMGF+1)*4;
        let exp = f32::from_le_bytes([raw[o2],raw[o2+1],raw[o2+2],raw[o2+3]]) as u16;
        let got = pick_zenpng_lossless_heuristic(&feats, zq);
        if got == exp { ok += 1; } else { eprintln!("MISMATCH case {k}: got {got} exp {exp}"); }
    }
    println!("VERIFIED {}/{} cases byte-exact", ok, n);
    if ok != n { std::process::exit(1); }
}
